package co.edu.elecciones.controller; import co.edu.elecciones.commons.dto.ApiResponse; import co.edu.elecciones.dto.Requests.ChatRequest; import co.edu.elecciones.dto.Responses.ChatResponse; import co.edu.elecciones.service.PredictionService; import co.edu.elecciones.repository.*; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/chat") public class ChatController { private final PredictionService predictions; private final OfficialResultRepository results; private final PollRepository polls; public ChatController(PredictionService p,OfficialResultRepository r,PollRepository po){predictions=p;results=r;polls=po;} @PostMapping("/ask") public ApiResponse<ChatResponse> ask(@RequestBody ChatRequest req){ String q=req.question()==null?"":req.question().toLowerCase(); if(q.contains("encuesta")) return ApiResponse.ok("OK",new ChatResponse("Tengo "+polls.count()+" encuestas registradas. Recuerda: Predicción ≠ resultado oficial.",List.of("consultar_encuestas"))); if(q.contains("predic")) return ApiResponse.ok("OK",new ChatResponse("La predicción actual por resultados parciales es: "+predictions.byPartialResults(),List.of("generar_resumen"))); return ApiResponse.ok("OK",new ChatResponse("Resultados oficiales cargados: "+results.count()+" registros. Puedo consultar resultados, encuestas, candidatos y partidos usando herramientas MCP autorizadas.",List.of("consultar_resultados"))); }}
